package concrete.goonie.chart.api.data.render; import concrete.goonie.chart.api.data.TextDataSet; import concrete.goonie.chart.internal.render.*; public final class TextDataSetRenderer { public void render(TextDataSet d, RenderList out, Transform t, int visibleFrom, int visibleTo){ int from=Math.max(0,visibleFrom), to=Math.min(d.sizeValue()-1,visibleTo); for(int i = from; i<=to; i++) out.add(new RenderCommand.Text(t.worldToScreenX(d.xValue(i)), t.worldToScreenY(d.yValue(i)), d.text(i), 11f, d.getTextStyle())); } }